protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve EF8 discriminator property name so existing documents
    // and raw SQL queries (WHERE c.Discriminator = 'Blog') keep working.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve EF8 compound id format ("Blog|1") for existing documents.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB throws at startup in EF Core 9.
    // Manage indexing via the container's indexing policy in Azure.
}

